import React from "react"
import Helmet from "react-helmet"
import { Tooltip, Typography, Box, withStyles } from "@material-ui/core"
import "@google/model-viewer/dist/model-viewer"
// import '@google/model-viewer'

import modelCss from "!raw-loader!../../css/model-viewer.css"
import models from "../../datasheet/models.yml"
import models_extras from "./models-extras"
import InfoIcon from "@material-ui/icons/Info"

const ModelTooptip = withStyles(theme => {
  return {
    tooltip: {
      background: "#fbf8f4",
      color: "#22254f",
      borderRadius: 0,
      boxShadow: "0 0 1rem #3332",
      padding: theme.spacing(2),
    },
  }
})(Tooltip)

const ShowModelViewer = ({ hotspots, poster, text = "3D model", ...props }) => {
  return (
    <>
      <Helmet>
        <style>{modelCss}</style>
      </Helmet>
      <Typography variant="overline" color="textSecondary">
        <Box display="flex" alignItems="center" justifyContent="space-between">
          {text}
          {models_extras[text] && (
            <ModelTooptip
              placement="left-start"
              title={models_extras[text]}
              enterTouchDelay={150}
            >
              <InfoIcon />
            </ModelTooptip>
          )}
        </Box>
      </Typography>

      <model-viewer
        camera-controls
        reveal="interaction"
        {...props}
        class="wave-border"
      >
        {
          // This poster slot is only meant to support webp format with fallback option
          // While it could also provide the ability to fix hotspot reveal problem
          // And give the cursor: pointer
        }
        <div slot="poster" className="custom-poster-container wave-border">
          <picture>
            <source srcSet={poster} type="image/webp" />
            <source srcSet={poster.replace("webp", "png")} type="image/png" />
            <img
              src={poster.replace("webp", "png")}
              alt={text}
              className="custom-poster"
            />
          </picture>
        </div>
        {hotspots.map(({ text, ...data }, index) => {
          const uid = `hotspot-${index + 1}`
          return (
            <button
              key={uid}
              slot={uid}
              className="Hotspot"
              data-visibility-attribute="visible"
              {...data}
            >
              <div className="HotspotAnnotation" children={text} />
            </button>
          )
        })}
      </model-viewer>
    </>
  )
}

export default () => {
  return (
    <div>
      <Helmet>
        <script
          src="https://unpkg.com/focus-visible@5.1.0/dist/focus-visible.js"
          defer
        />
      </Helmet>
      {models.map(model => {
        return <ShowModelViewer key={model.src} {...model} />
      })}
    </div>
  )
}
